var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"구 카스피 해 동부 무인지대 2300미터 상공.","JPN":"旧カスピ海東部の無人地帯2300メートル上空。","ENG":"2,300 meters in the air, east of no-man's land of the former Caspian Sea.","TWN":"舊裡海，無人區以東，2300ｍ高空。","SCN":"前里海，无人区以东，2300米的高空。","DEU":"2,300 meters in the air, east of no-man's land of the former Caspian Sea.","FRA":"2,300 meters in the air, east of no-man's land of the former Caspian Sea."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"북방합의체 영토 진입까지 약 20분.","JPN":"北方合意体領土進入まで約20分。","ENG":"Approximately 20 minutes until reaching Northern Union territory.","TWN":"大約20分鐘後進入北方和議會領空。","SCN":"大约20分钟后进入北方联盟领空。","DEU":"Approximately 20 minutes until reaching Northern Union territory.","FRA":"Approximately 20 minutes until reaching Northern Union territory."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PILOT_VOICE_ADMIN_NULL","text":{"KOREA":"침식파 농도가 계속 높아지고 있습니다. 침식체가 출몰할 가능성이 있으니 대비하십시오.","JPN":"侵食波の濃度がだんだん高くなっています。侵食体が出現する可能性がありますので、備えてください。","ENG":"The Corruption ray density is continuing to rise. Be ready for any C.O.s that might appear.","TWN":"目前侵蝕波濃度持續上升中。請做好準備，可能會出現侵蝕體。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어째 로터스를 벗어난 순간부터 침식파가 얌전해지는 구간이 하나도 없네요.","JPN":"なんだかロータスを離れた瞬間から侵食波が落ち着く区域がまったくないですね。","ENG":"How is there no place where Corruption rays are calm from the moment we left Lotus?","TWN":"怎麼一離開洛德斯，侵蝕波就沒一刻平靜過呢……"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저기 보이는 마천루도 예전엔 엄청 많은 사람들이 살았겠죠?","JPN":"あそこに見える摩天楼にも、昔は人がいっぱい住んでたんでしょうか？","ENG":"A lot of people must have lived in that skyscraper over there in the past, right?","TWN":"那邊的摩天樓，以前一定住了很多人吧？"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"20년 전엔 그랬죠.","JPN":"20年前はそうでした。","ENG":"They did 20 years ago.","TWN":"20年前是的。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"로터스와 북방합의체 사이엔 폭이 2천 킬로미터에 달하는 무주지가 있지만, 지금은 전부 사람 하나 살지 않는 준위험 침식지대일 뿐입니다.","JPN":"ロータスと北方合意体の間には幅2千キロメートルにも達する無住地がありますが、今は誰も住んでいない準危険侵食地帯であるだけです。","ENG":"There is a 2,000-kilometer-wide terra nullius between Lotus and the Northern Union. But now, it's a semi-hazardous Corrupted Area where no one lives.","TWN":"洛德斯和北方和議會之間有一片長達2000公里的無人區，現在全都是沒人居住的危險侵蝕地帶。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우리가 지나는 곳이 과거엔 제법 유명한 휴양지였다네.","JPN":"私たちが通り過ぎた場所は、昔有名なリゾート地だったんだ。","ENG":"The place we are passing by used to be a fairly popular resort.","TWN":"我們經過的地方曾經是相當有名的度假勝地。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크리스 양이 과거에 태어났다면 저기 어딘가에서 여름 휴가를 보내고 있었을지도 모르지.","JPN":"クリス君がもっと前に生まれていたら、あそこで夏休みを満喫していたのかもしれないね。","ENG":"If you were born in the past, you could've been spending your summer vacation somewhere over there, Chris.","TWN":"克莉絲，你如果出生在過去，可能會在這裡的某個地方度過暑假喔。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"과거에 태어나도 형편이 비슷하면 어렵지 않을까요?","JPN":"もっと前に生まれても似たような状況だったら難しいと思いますよ。","ENG":"Wouldn't it still be difficult if I was born in the past and still poor?","TWN":"即使生在過去，也許和現在也沒多大差別吧……？"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"살면서 대부분의 나날이 일하지 않으면 당장 내일을 굶어야 하는 형편이었거든요.","JPN":"ほぼ毎日働かないと、翌日には食べる物がない状況でしたから。","ENG":"Because for most of my life, I was in a situation where if I didn't work, I had to starve the next day.","TWN":"畢竟我窮到不工作的話，明天就得繼續挨餓……"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"저런. 그런 과거가 있었다니 유감입니다.","JPN":"あら。そんな過去をお持ちだったとはお気の毒です。","ENG":"Oh. I'm sorry to hear that about your past.","TWN":"真遺憾，沒想到你有那樣的過去。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아……","JPN":"あ……","ENG":"Ah...","TWN":"啊……"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"분위기 망쳐서 죄송합니다. 역시 전 말을 아끼는 편이 어울려요.","JPN":"気まずくしてごめんなさい。やっぱり私は喋らない方がいいですね。","ENG":"I'm sorry for ruining the mood. I guess I should just keep my mouth shut.","TWN":"破壞氣氛，真是抱歉。我果然還是少說話比較好……"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크흠, 그럼 요즘 이야기로 화제를 바꾸는 게 좋겠군.","JPN":"コホン、では最近の話に話題を変えるとしよう。","ENG":"Ahem. Then, how about we change topics?","TWN":"咳咳，那我們還是聊聊最近的事情吧。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크리스 양은 우리가 향하는 북방합의체에 대해 얼마나 알고 있지?","JPN":"クリス君は、私たちが向かっている北方合意体についてどれぐらい知っているのかね？","ENG":"Chris, how much do you know about the Northern Union?","TWN":"克莉絲，你對我們要去的北方和議會了解多少？"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"틈만 나면 주변 나라에 시비를 건다거나 그 나라 전체가 관리거부지역이라는 것 정도요.","JPN":"隙あらば周りの国にケンカを売るとか、その国全体が管理拒否地域ってことくらいです。","ENG":"I know that they'll start a fight with neighboring countries whenever they have a chance, and that the entire nation is an Anti-Administration zone.","TWN":"我？我只知道他們一有機會就與周邊國家挑起爭端，而且整個國家都被劃作拒絕管理區域。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"관리국의 지원을 받지 않는데도 내전이 전혀 없는 곳이라고 들었어요.","JPN":"管理局からの支援を拒否しているのに、内戦がまったく起こらないところだと聞きました。","ENG":"I also heard that there are no civil wars despite not receiving support from the Administration.","TWN":"不過我聽說那裡雖然沒有得到管理局的支持，但也完全沒有內戰……"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"총참모장 한 명의 정치적 영향력이 압도적으로 강하기 때문이죠.","JPN":"総参謀長の政治的な影響力が圧倒的に強いからです。","ENG":"That's only possible because the Chief of the General Staff's political influence is overwhelmingly powerful.","TWN":"因為他們的參謀總長政治影響力極其強大。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"얼마 전, 당국과 논의 없이 외부 기업 스파이를 처형했단 이유로 현재 근신 중에 있습니다.","JPN":"当局との話し合いもなく、先日外部企業のスパイを処刑したという理由で只今謹慎中です。","ENG":"Recently, I heard she is under probation for executing an external corporate spy without getting the party's approval first.","TWN":"不過不久前，因為未經當局批准就處決了一名外部企業的間諜，目前正在接受調查。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아, 뉴스에서 봤어요. 이름이 펠릭스였죠?","JPN":"あ、ニュースで見ました。名前はフェリックスでしたよね？","ENG":"Oh, I saw that on the news too. Felix, was it?","TWN":"啊，我在新聞上看到了。名字叫緋莉克絲，對吧？"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"언론은 그 사람을 사적 제재를 일삼는 살인마로 취급하던데, 정작 국민들은 시위까지 벌이면서 펠릭스를 옹호하더라고요.","JPN":"マスコミはあの人を私的制裁を加える殺人鬼だって言ってましたけど、国民はデモを起こしてまでフェリックスのことを擁護してました。","ENG":"The media seems to frame that person as some murderer who loves to lynch. But the public seems to defend Felix by throwing a protest.","TWN":"媒體似乎把那個人批判成私刑犯，但民眾卻舉行示威支持她……"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"펠릭스는 부친과 함께 대정화전쟁 이후 체제가 무너진 시베리아와 극동 일대를 하나로 규합한 구국의 영웅이니까요.","JPN":"フェリックスは父親とともに、大浄化戦争以後秩序が崩壊したシベリアと極東の一帯を1つに糾合した救国の英雄ですから。","ENG":"That's because Felix, along with her father, is a national hero of the old republic who united the fallen regimes of Siberia and the Far East after the Grand Purification War.","TWN":"因為那個女人和她的父親一起，在大淨化作戰後統一了體制崩潰的西伯利亞和遠東地區，在不少人眼裡是國家的英雄。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"하지만 그녀가 정권을 쥐는 것에 반대하는 온건파 관료들의 견제로 자주 구설수에 오르곤 하죠.","JPN":"ですが、彼女が政権を掌握することに反対した穏健派の官僚たちの牽制によってよく話題のタネになっています。","ENG":"But she is often criticized by the Progressive Party who oppose her taking power.","TWN":"但是，在反對她掌權的溫和派官員的牽制下，經常被捲入爭議。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그녀요…? 펠릭스가 여자 이름이었나요?","JPN":"彼女……？　フェリックスって女性の名前だったんですか？","ENG":"Wait a minute... Felix is a girl's name?","TWN":"女生……？緋莉克絲聽起來好像是男生的名字……？"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"일종의 상징입니다. 당시 규합을 주도했던 부친의 이름을 그대로 물려받았으니까요.","JPN":"一種の象徴です。当時糾合を主導した父親の名前をそのまま受け継ぎましたから。","ENG":"It's more like a symbolic name. She inherited her father's name, who led the rally at the time.","TWN":"她父親是黨派的領導人，因此她繼承父親的名字，象徵一種傳承。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};